import Foundation

enum NetworkError: Error {
    case invalidURL
    case dataTaskError(Error)
}

struct NetworkManager {
    private let session = URLSession.shared
    private var baseURL: String

    init(baseURL: String) {
        self.baseURL = baseURL
    }

    func get(from endpoint: String, completion: @escaping (Result<Data, NetworkError>) -> Void) {
        let url = URL(string("\(baseURL)\(endpoint)"))!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"

        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(NetworkError.dataTaskError(error)))
                return
            }

            guard let data = data else {
                completion(.failure(NetworkError.invalidURL))
                return
            }

            completion(.success(data))
        }

        task.resume()
    }

    func post(to endpoint: String, data: Data, completion: @escaping (Result<Data, NetworkError>) -> Void) {
        let url = URL(string("\(baseURL)\(endpoint)"))!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = data
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(NetworkError.dataTaskError(error)))
                return
            }

            guard let data = data else {
                completion(.failure(NetworkError.invalidURL))
                return
            }

            completion(.success(data))
        }

        task.resume()
    }
}